select count(*) from nums;

with recursive rec(id, mul0) as (
	select 0, 1
	union all 
	select (rec.id + 1), (mul0 * nums.num) % 1000 from rec
	join nums on nums.id = (rec.id + 1) 
	where (rec.id + 1) <= (select count(*) from nums) 
	
)
select  mul0 mul_mod1000 from rec
where rec.id > 0
order by rec.id DESC
limit 1;
